export function emitJavaContext(packageName: string): string {
  return [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    `package ${packageName};`,
    "",
    "import java.util.Map;",
    "import java.util.function.Function;",
    "",
    "public final class LoadContext {",
    "  private final Function<Object, Object> preProcess;",
    "  private final Function<Object, Object> postProcess;",
    "",
    "  public LoadContext() {",
    "    this(null, null);",
    "  }",
    "",
    "  public LoadContext(Function<Object, Object> preProcess, Function<Object, Object> postProcess) {",
    "    this.preProcess = preProcess;",
    "    this.postProcess = postProcess;",
    "  }",
    "",
    "  public Object processInput(Object value) {",
    "    return preProcess == null ? value : preProcess.apply(value);",
    "  }",
    "",
    "  @SuppressWarnings(\"unchecked\")",
    "  public <T> T processOutput(T value) {",
    "    return postProcess == null ? value : (T) postProcess.apply(value);",
    "  }",
    "}",
    "",
  ].join("\n");
}

export function emitJavaSaveContext(packageName: string): string {
  return [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    `package ${packageName};`,
    "",
    "import java.util.Map;",
    "import java.util.function.Function;",
    "",
    "public final class SaveContext {",
    "  private final Function<Object, Object> preSave;",
    "  private final Function<Map<String, Object>, Map<String, Object>> postSave;",
    "",
    "  public SaveContext() {",
    "    this(null, null);",
    "  }",
    "",
    "  public SaveContext(Function<Object, Object> preSave, Function<Map<String, Object>, Map<String, Object>> postSave) {",
    "    this.preSave = preSave;",
    "    this.postSave = postSave;",
    "  }",
    "",
    "  @SuppressWarnings(\"unchecked\")",
    "  public <T> T processObject(T value) {",
    "    return preSave == null ? value : (T) preSave.apply(value);",
    "  }",
    "",
    "  public Map<String, Object> processDict(Map<String, Object> value) {",
    "    return postSave == null ? value : postSave.apply(value);",
    "  }",
    "}",
    "",
  ].join("\n");
}

export function emitJavaMaps(packageName: string): string {
  return [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    `package ${packageName};`,
    "",
    "import java.util.LinkedHashMap;",
    "import java.util.Map;",
    "",
    "public final class TypraMaps {",
    "  private TypraMaps() { }",
    "",
    "  public static Map<String, Object> mapOf(Object... pairs) {",
    "    Map<String, Object> result = new LinkedHashMap<>();",
    "    for (int i = 0; i + 1 < pairs.length; i += 2) {",
    "      result.put(String.valueOf(pairs[i]), pairs[i + 1]);",
    "    }",
    "    return result;",
    "  }",
    "}",
    "",
  ].join("\n");
}

export function emitJavaJson(packageName: string): string {
  return [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    `package ${packageName};`,
    "",
    "import java.util.Iterator;",
    "import java.util.ArrayList;",
    "import java.util.LinkedHashMap;",
    "import java.util.List;",
    "import java.util.Map;",
    "",
    "public final class TypraJson {",
    "  private TypraJson() { }",
    "",
    "  public static String stringify(Object value) {",
    "    if (value == null) return \"null\";",
    "    if (value instanceof String s) return \"\\\"\" + escape(s) + \"\\\"\";",
    "    if (value instanceof Number || value instanceof Boolean) return String.valueOf(value);",
    "    if (value instanceof Map<?, ?> map) {",
    "      StringBuilder builder = new StringBuilder(\"{\");",
    "      Iterator<? extends Map.Entry<?, ?>> iterator = map.entrySet().iterator();",
    "      while (iterator.hasNext()) {",
    "        Map.Entry<?, ?> entry = iterator.next();",
    "        builder.append(stringify(String.valueOf(entry.getKey()))).append(':').append(stringify(entry.getValue()));",
    "        if (iterator.hasNext()) builder.append(',');",
    "      }",
    "      return builder.append('}').toString();",
    "    }",
    "    if (value instanceof Iterable<?> iterable) {",
    "      StringBuilder builder = new StringBuilder(\"[\");",
    "      Iterator<?> iterator = iterable.iterator();",
    "      while (iterator.hasNext()) {",
    "        builder.append(stringify(iterator.next()));",
    "        if (iterator.hasNext()) builder.append(',');",
    "      }",
    "      return builder.append(']').toString();",
    "    }",
    "    return stringify(String.valueOf(value));",
    "  }",
    "",
    "  public static Object parse(String json) {",
    "    Parser parser = new Parser(json);",
    "    Object value = parser.parseValue();",
    "    parser.skipWhitespace();",
    "    if (!parser.isAtEnd()) {",
    "      throw new IllegalArgumentException(\"Unexpected trailing JSON content at offset \" + parser.index);",
    "    }",
    "    return value;",
    "  }",
    "",
    "  private static String escape(String value) {",
    "    return value.replace(\"\\\\\", \"\\\\\\\\\").replace(\"\\\"\", \"\\\\\\\"\").replace(\"\\r\", \"\\\\r\").replace(\"\\n\", \"\\\\n\");",
    "  }",
    "",
    "  private static final class Parser {",
    "    private final String input;",
    "    private int index;",
    "",
    "    Parser(String input) {",
    "      this.input = input == null ? \"\" : input;",
    "    }",
    "",
    "    boolean isAtEnd() {",
    "      return index >= input.length();",
    "    }",
    "",
    "    void skipWhitespace() {",
    "      while (!isAtEnd() && Character.isWhitespace(input.charAt(index))) index++;",
    "    }",
    "",
    "    Object parseValue() {",
    "      skipWhitespace();",
    "      if (isAtEnd()) throw error(\"Unexpected end of JSON input\");",
    "      char ch = input.charAt(index);",
    "      if (ch == '{') return parseObject();",
    "      if (ch == '[') return parseArray();",
    "      if (ch == '\"') return parseString();",
    "      if (ch == 't') return parseLiteral(\"true\", Boolean.TRUE);",
    "      if (ch == 'f') return parseLiteral(\"false\", Boolean.FALSE);",
    "      if (ch == 'n') return parseLiteral(\"null\", null);",
    "      if (ch == '-' || Character.isDigit(ch)) return parseNumber();",
    "      throw error(\"Unexpected JSON token\");",
    "    }",
    "",
    "    private Map<String, Object> parseObject() {",
    "      expect('{');",
    "      Map<String, Object> result = new LinkedHashMap<>();",
    "      skipWhitespace();",
    "      if (tryConsume('}')) return result;",
    "      while (true) {",
    "        skipWhitespace();",
    "        String key = parseString();",
    "        skipWhitespace();",
    "        expect(':');",
    "        result.put(key, parseValue());",
    "        skipWhitespace();",
    "        if (tryConsume('}')) return result;",
    "        expect(',');",
    "      }",
    "    }",
    "",
    "    private List<Object> parseArray() {",
    "      expect('[');",
    "      List<Object> result = new ArrayList<>();",
    "      skipWhitespace();",
    "      if (tryConsume(']')) return result;",
    "      while (true) {",
    "        result.add(parseValue());",
    "        skipWhitespace();",
    "        if (tryConsume(']')) return result;",
    "        expect(',');",
    "      }",
    "    }",
    "",
    "    private String parseString() {",
    "      expect('\"');",
    "      StringBuilder result = new StringBuilder();",
    "      while (!isAtEnd()) {",
    "        char ch = input.charAt(index++);",
    "        if (ch == '\"') return result.toString();",
    "        if (ch != '\\\\') {",
    "          result.append(ch);",
    "          continue;",
    "        }",
    "        if (isAtEnd()) throw error(\"Unterminated JSON escape sequence\");",
    "        char escaped = input.charAt(index++);",
    "        switch (escaped) {",
    "          case '\"' -> result.append('\"');",
    "          case '\\\\' -> result.append('\\\\');",
    "          case '/' -> result.append('/');",
    "          case 'b' -> result.append('\\b');",
    "          case 'f' -> result.append('\\f');",
    "          case 'n' -> result.append('\\n');",
    "          case 'r' -> result.append('\\r');",
    "          case 't' -> result.append('\\t');",
    "          case 'u' -> result.append(parseUnicodeEscape());",
    "          default -> throw error(\"Unsupported JSON escape sequence\");",
    "        }",
    "      }",
    "      throw error(\"Unterminated JSON string\");",
    "    }",
    "",
    "    private char parseUnicodeEscape() {",
    "      if (index + 4 > input.length()) throw error(\"Incomplete unicode escape\");",
    "      String hex = input.substring(index, index + 4);",
    "      index += 4;",
    "      try {",
    "        return (char) Integer.parseInt(hex, 16);",
    "      } catch (NumberFormatException error) {",
    "        throw error(\"Invalid unicode escape\");",
    "      }",
    "    }",
    "",
    "    private Object parseLiteral(String literal, Object value) {",
    "      if (!input.startsWith(literal, index)) throw error(\"Invalid JSON literal\");",
    "      index += literal.length();",
    "      return value;",
    "    }",
    "",
    "    private Number parseNumber() {",
    "      int start = index;",
    "      if (input.charAt(index) == '-') index++;",
    "      while (!isAtEnd() && Character.isDigit(input.charAt(index))) index++;",
    "      boolean floating = false;",
    "      if (!isAtEnd() && input.charAt(index) == '.') {",
    "        floating = true;",
    "        index++;",
    "        while (!isAtEnd() && Character.isDigit(input.charAt(index))) index++;",
    "      }",
    "      if (!isAtEnd() && (input.charAt(index) == 'e' || input.charAt(index) == 'E')) {",
    "        floating = true;",
    "        index++;",
    "        if (!isAtEnd() && (input.charAt(index) == '+' || input.charAt(index) == '-')) index++;",
    "        while (!isAtEnd() && Character.isDigit(input.charAt(index))) index++;",
    "      }",
    "      String text = input.substring(start, index);",
    "      try {",
    "        if (floating) return Double.parseDouble(text);",
    "        long longValue = Long.parseLong(text);",
    "        return longValue >= Integer.MIN_VALUE && longValue <= Integer.MAX_VALUE ? (int) longValue : longValue;",
    "      } catch (NumberFormatException error) {",
    "        throw error(\"Invalid JSON number\");",
    "      }",
    "    }",
    "",
    "    private boolean tryConsume(char expected) {",
    "      if (!isAtEnd() && input.charAt(index) == expected) {",
    "        index++;",
    "        return true;",
    "      }",
    "      return false;",
    "    }",
    "",
    "    private void expect(char expected) {",
    "      if (isAtEnd() || input.charAt(index) != expected) throw error(\"Expected '\" + expected + \"'\");",
    "      index++;",
    "    }",
    "",
    "    private IllegalArgumentException error(String message) {",
    "      return new IllegalArgumentException(message + \" at offset \" + index);",
    "    }",
    "  }",
    "}",
    "",
  ].join("\n");
}
